def main() -> int:
    failures: list[str] = []
    successes: list[tuple[str, int, int]] = []  # (path, old_words, new_words)
    for rel_path, old, new in REPLACEMENTS:
        path = REPO / rel_path
        text = path.read_text(encoding="utf-8")
        if old not in text:
            failures.append(f"{rel_path}: old text not found")
            continue
        if text.count(old) > 1:
            failures.append(f"{rel_path}: old text matches multiple locations ({text.count(old)} times)")
            continue
        new_text = text.replace(old, new)
        path.write_text(new_text, encoding="utf-8")
        successes.append((rel_path, len(old.split()), len(new.split())))

    print(f"=== Phase 0a HIGH-tier compression results ===")
    print(f"Replacements applied: {len(successes)} of {len(REPLACEMENTS)}")
    if successes:
        total_old = sum(s[1] for s in successes)
        total_new = sum(s[2] for s in successes)
        print(f"Total words: {total_old} -> {total_new} (delta {total_new - total_old})")
        print()
        for rel_path, old_w, new_w in successes:
            print(f"  {rel_path:<70} {old_w:>4}w -> {new_w:>4}w")
    if failures:
        print()
        print(f"Failures ({len(failures)}):")
        for f in failures:
            print(f"  {f}")
        return 1
    return 0


if __name__ == "__main__":
    sys.exit(main())
